fn update_borders_menu(
    _backend: &mut dyn Backend,
    _changes: &[(&str, &str)],
    events: &[InputEvent],
) -> Option<Menu> {
    for ev in events {
        if let InputEvent::Press { x, y } = ev {
            if *x < 400 && *y < 80 {
                if let Some(m) = super::nav(&["Widget"]) { return Some(m); }
            }
            if *x >= 400 && *x < 800 && *y < 80 {
                if let Some(m) = super::nav(&["Clickable"]) { return Some(m); }
            }
        }
    }
    None
}

