fn update_widget_menu(
    backend: &mut dyn Backend,
    changes: &[(&str, &str)],
    events: &[InputEvent],
) -> Option<Menu> {
    backend.render(&mut |fb, stride| {
        for &(name, val) in changes {
            if name == "parameter One" {
                atlas_1().blit(fb, stride, 0, 284,
                    &format!("{:<47}", val));
            }
        }
    });
    for &(name, val) in changes {
        if name == "parameter Two" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (800.0_f32 * v) as usize;
                if filled > 0 {
                    backend.fill_rect(0, 360, filled, 120, rgb!(255, 255, 255));
                }
                if filled < 800 {
                    backend.fill_rect(filled, 360, 800 - filled, 120, rgb!(0, 0, 0));
                }
            }
        }
    }
    for ev in events {
        if let InputEvent::Press { x, y } = ev {
            if *x < 400 && *y < 120 {
                if let Some(m) = super::nav(&["Unequal"]) { return Some(m); }
            }
            if *x >= 400 && *x < 800 && *y < 120 {
                if let Some(m) = super::nav(&["Borders"]) { return Some(m); }
            }
        }
    }
    None
}

